def is_valid_ipv4(s: str) -> bool:
    if not isinstance(s, str):
        return False

    # Check for whitespace
    if s != s.strip():
        return False

    # Split by dot
    parts = s.split('.')

    # Must have exactly 4 parts
    if len(parts) != 4:
        return False

    for part in parts:
        # Each part must not be empty
        if not part:
            return False

        # Each part must consist only of digits
        if not part.isdigit():
            return False

        # No leading zeros allowed (except for the single digit '0')
        if len(part) > 1 and part[0] == '0':
            return False

        # Convert to integer and check range
        try:
            num = int(part)
        except ValueError:
            return False

        if num < 0 or num > 255:
            return False

    return True

