def is_valid_ipv4(s: str) -> bool:
    """
    Returns True if s is a strictly-valid IPv4 address in dotted notation.
    Rejects leading zeros, out-of-range octets, non-digits, and incorrect part counts.
    """
    # Split the string by dots
    parts = s.split('.')

    # Requirement: exactly 4 octets
    if len(parts) != 4:
        return False

    for part in parts:
        # Requirement: reject empty strings (e.g., '1.2..4') or whitespace
        if not part:
            return False

        # Requirement: reject non-digit characters (handles negative signs and whitespace)
        if not part.isdigit():
            return False

        # Requirement: NO leading zeros allowed (except for the single digit '0')
        if len(part) > 1 and part[0] == '0':
            return False

        # Requirement: each octet is a base-10 integer in [0, 255]
        try:
            val = int(part)
            if not (0 <= val <= 255):
                return False
        except ValueError:
            return False

    return True

